const rawOutput = $json.output[0].content[0].text;

/**
 * Flexible extractor for "Label: Value" patterns.
 * Matches: Label: "Value", Label: Value, or Label: ["Value"]
 */
const extract = (label) => {
  // Escapes special characters and looks for the label followed by a colon or equals sign
  const regex = new RegExp(`${label}\\s*[:=]\\s*(?:(?:\\[?\\s*")|(?:\\[?\\s*))([^"\\n\\]]+)`, 'i');
  const match = rawOutput.match(regex);
  return match ? match[1].trim() : "";
};

