const text = $json.output[0].content[0].text;

/**
 * Extracts all text between two string markers and cleans it.
 */
const getSection = (startMarker, endMarker) => {
  const startLabel = `${startMarker}:`;
  const startIndex = text.indexOf(startLabel);

  if (startIndex === -1) return "";

  const contentStart = startIndex + startLabel.length;
  let contentEnd;

  if (endMarker) {
    const endLabel = `${endMarker}:`;
    contentEnd = text.indexOf(endLabel);
  }

  // If no end marker is found, capture to the end
  if (!contentEnd || contentEnd === -1) {
    contentEnd = text.length;
  }

  const rawContent = text.substring(contentStart, contentEnd).trim();

  // CLEANING LOGIC:
  // 1. Remove asterisks (*), hyphens (-), and hash symbols (#)
  // 2. KEEP double quotes (") 
  // 3. Trim extra whitespace and collapse empty lines
  return rawContent
    .replace(/[*#\-]/g, "")      // Removed " from this list to keep quotes
    .replace(/^\s*[\r\n]/gm, "")  // Removes empty lines created by cleaning
    .trim();
};

