const inputData = $input.item.json.output?.[0]?.content?.[0]?.text || $input.first().json.text || "";

/**
 * Helper function to extract Score as a Number and Analysis text
 * Supports: "Score: 20/25" OR "Score: 20 out of 25"
 */
const parseSection = (marker, source) => {
  // Regex breakdown:
  // (?:Score:\s*)?          -> Optional "Score: " prefix
  // (\d+)                   -> Group 1: The actual score
  // \s*(?:\/|out\s+of)\s* -> Match "/" OR "out of"
  // (\d+)                   -> Group 2: The max score
  // [.\s]* -> Match period or whitespace
  // ([\s\S]*?)              -> Group 3: The analysis text
  // (?=\n###|$)             -> Stop at the next header or end of string
  const regex = new RegExp(`${marker}\\s*[\\r\\n]+(?:Score:\\s*)?(\\d+)\\s*(?:\\/|out\\s+of)\\s*(\\d+)[.\\s]*([\\s\\S]*?)(?=\\n###|$)`, "i");

  const match = source.match(regex);

  if (match) {
    return {
      score: parseInt(match[1], 10), 
      analysis: match[3].trim()
    };
  }
  return { score: 0, analysis: "Section not found" };
};

// 2. Extract Overall Alignment Score (usually at the top)
const scoreMatch = inputData.match(/Alignment Score:\s*(\d+)\s*(?:\/|out\s+of)\s*(\d+)/i);
