function extractByKeys(str, startKey, endKey) {
  const lowerStr = str.toLowerCase();

  // 1. Find where the Key Name starts
  const keyIdx = lowerStr.indexOf(startKey.toLowerCase());
  if (keyIdx === -1) return "";

  // 2. Find the FIRST double quote AFTER the Key Name
  // This skips colons, spaces, and stray letters like "o" or "l 1"
  const valueStartMarker = str.indexOf('"', keyIdx + startKey.length);
  if (valueStartMarker === -1) return "";

  const valueStart = valueStartMarker + 1;
  let extracted = "";

  if (endKey) {
    // 3. Find the End Key
    const endIdx = lowerStr.indexOf(endKey.toLowerCase(), valueStart);
    if (endIdx !== -1) {
      // Look back from the End Key to find the closing quote of our value
      const closingQuote = str.lastIndexOf('"', endIdx);
      extracted = (closingQuote > valueStart) ? str.substring(valueStart, closingQuote) : str.substring(valueStart, endIdx);
    } else {
      extracted = str.substring(valueStart);
    }
  } else {
    // 4. For the last item, find the very last quote in the string
    const lastQuote = str.lastIndexOf('"');
    extracted = (lastQuote > valueStart) ? str.substring(valueStart, lastQuote) : str.substring(valueStart);
  }

  // 5. Clean up escape characters and newlines
  return extracted
    .replace(/\\"/g, '"') 
    .replace(/\\n/g, ' ')
    .trim();
}

