// Optimized to handle Workday JSON-LD and heavy CSS bloat

function extractUniversal(html) {
  if (!html || html.length < 100) return "Error: HTML too short or empty.";

  // --- STRATEGY 1: The JSON-LD Payload (Highest Accuracy) ---
  // We saw this in your PayPal output. It contains the clean text.
  const jsonLdMatch = html.match(/<script type="application\/ld\+json">([\s\S]*?)<\/script>/i);
  if (jsonLdMatch) {
    try {
      const data = JSON.parse(jsonLdMatch[1]);
      // Workday usually nests this or puts it in an array
      const rawDesc = data.description || (Array.isArray(data) ? data[0].description : null);

      if (rawDesc) {
        return rawDesc
          .replace(/<[^>]+>/g, '\n') // Remove HTML tags
          .replace(/&amp;/g, '&')
          .replace(/&nbsp;/g, ' ')
          .replace(/\n\s*\n/g, '\n\n')
          .trim();
      }
    } catch (e) { /* Fallback to Strategy 2 */ }
  }

  // --- STRATEGY 2: The Aggressive Body Clean ---
  const bodyMatch = html.match(/<body[^>]*>([\s\S]*)<\/body>/i);
  let content = bodyMatch ? bodyMatch[1] : html;

  return content
    // 1. Kill the heavy stuff immediately
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<svg[\s\S]*?<\/svg>/gi, ' ')
    // 2. Kill the CSS variable lists (the --cnvs-base stuff bloat)
    .replace(/--[a-zA-Z0-9-]+:[^;]+;/g, ' ')
    // 3. Structural conversion
    .replace(/<h[1-6][^>]*>([\s\S]*?)<\/h[1-6]>/gi, '\n### $1\n')
    .replace(/<li>([\s\S]*?)<\/li>/gi, '\n* $1')
    .replace(/<(p|br|div)[^>]*>/gi, '\n')
    // 4. Final tag strip and whitespace compression
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n\s*\n/g, '\n\n')
    .trim();
}

return $input.all().map(item => {
