const returnItems = [];

for (const item of $input.all()) {
  // 1. Retrieve the inputs. 
  // Update 'resumeText' to whatever field holds your resume in the previous node.
  const resumeText = $input.item.json.text || item.json.text || ""; 

  // 2. Define the skills (reads from input if available, otherwise uses your defaults)
  const skill1 = $('Get Rows For Emails').all()[$('Download Resume For Email').item.json.row_number-2].json['BIG SIX SKILL 1'];
  const skill2 = $('Get Rows For Emails').all()[$('Download Resume For Email').item.json.row_number-2].json['BIG SIX SKILL 2'];

  const lines = resumeText.split('\n');
  const extractedBullets = [];

  let currentSkill = null;
  let currentText = [];

  for (let i = 0; i < lines.length; i++) {
    let line = lines[i].trim();
    if (!line) continue;

    // Check if the current line starts a new bullet point
    if (line.startsWith('●')) {

      // If we were already capturing a previous skill, save it before moving on
      if (currentSkill && currentText.length > 0) {
        extractedBullets.push({
          skill: currentSkill,
          rawBullet: currentText.join(' '),
          // This strips the "● Skill Name:" prefix so you just get the achievement text
          cleanText: currentText.join(' ').replace(/^●\s*.*?:/, '').trim()
        });
        currentSkill = null;
        currentText = [];
      }

      // Check if this new bullet matches Skill 1 or Skill 2
      if (line.includes(skill1)) {
        currentSkill = skill1;
        currentText.push(line);
      } else if (line.includes(skill2)) {
        currentSkill = skill2;
        currentText.push(line);
      }

    } else {
      // If it's NOT a bullet point, but we are currently capturing a skill...
      if (currentSkill) {

        // Safety Check: Stop capturing if the line is an all-caps section header or company name
        // (e.g., "UNISYS INFOTECH") to prevent bleeding into the next job.
        if (/^[A-Z0-9\s\-,]+$/.test(line) && !/[a-z]/.test(line)) {
          extractedBullets.push({
            skill: currentSkill,
            rawBullet: currentText.join(' '),
            cleanText: currentText.join(' ').replace(/^●\s*.*?:/, '').trim()
          });
          currentSkill = null;
          currentText = [];
        } else {
          // It's a standard continuation of the bullet point onto the next line
          currentText.push(line);
        }
      }
    }
  }

  // Catch the very last bullet point if the resume ended while we were capturing
  if (currentSkill && currentText.length > 0) {
    extractedBullets.push({
      skill: currentSkill,
      rawBullet: currentText.join(' '),
      cleanText: currentText.join(' ').replace(/^●\s*.*?:/, '').trim()
    });
  }

  // 3. Attach the extracted data to the output
  returnItems.push({
    json: {
      ...item.json,
      skill1,
      skill2,
      extractedBullets: extractedBullets
    }
  });
}

