function extractJobDetails(html) {
  // Clean HTML to text with spaces (Used for Years and Visa)
  const textContent = html.replace(/<[^>]*>/g, ' ').replace(/&nbsp;/g, ' ').replace(/[-_]/g, ' ');
  const textLower = textContent.toLowerCase();

  // 2. Years Extraction
  const numberMap = { 'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5, 'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10 };

  const expPattern = /(?:minimum|at least|preferred|have|experience|años de)?\s*(?:\b(\d{1,2}|one|two|three|four|five|six|seven|eight|nine|ten)\s*(?:\s*(?:-|–|—|to)\s*\d{1,2})?\s*(?:\(\d+\))?\s*\+?)\s*(?:\+?|or more\s*)?(?:years?|años)(?:\s*(?:of\s*)?(?:experience|proven|required|minimum|at least|preferred|años de))?/i;

  const expMatch = textContent.match(expPattern);
  let yearsNum = 0; 
  let yearsText = 'Not mentioned';

  if (expMatch) {
    const rawMatch = expMatch[1].toLowerCase();
    yearsNum = numberMap[rawMatch] || parseInt(rawMatch);
    yearsText = expMatch[0].trim();
    if (yearsNum > 25) {
      yearsNum = 0;
      yearsText = 'Not mentioned';
    }
  } else if (textLower.includes("entry level") || textLower.includes("junior")) {
    yearsText = "Entry/Junior";
  }

  // 3. Visa Status
  const sponsorshipKeywords = ["visa sponsorship is available","will sponsor","willing to sponsor","sponsorship available","h1b sponsorship","h-1b sponsorship"];
  const restrictiveKeywords = ["us citizen","u.s. citizen","u.s. citizenship","green card","clearance required","no sponsorship","will not sponsor","not able to sponsor","not provide sponsorship"];

  let visaStatus = "Uncertain";
  if (sponsorshipKeywords.some(kw => textLower.includes(kw))) {
    visaStatus = "Yes";
  } else if (restrictiveKeywords.some(kw => textLower.includes(kw))) {
    visaStatus = "Restrictive (Citizen/GC/Clearance)";
  }

  // 4. UNIVERSAL LOCATION
  const stateAbbr = ['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY', 'DC'];
  const stateFull = ['Alabama','Alaska','Arizona','Arkansas','California','Colorado','Connecticut','Delaware','Florida','Georgia','Hawaii','Idaho','Illinois','Indiana','Iowa','Kansas','Kentucky','Louisiana','Maine','Maryland','Massachusetts','Michigan','Minnesota','Mississippi','Missouri','Montana','Nebraska','Nevada','New Hampshire','New Jersey','New Mexico','New York','North Carolina','North Dakota','Ohio','Oklahoma','Oregon','Pennsylvania','Rhode Island','South Carolina','South Dakota','Tennessee','Texas','Utah','Vermont','Virginia','Washington','West Virginia','Wisconsin','Wyoming', 'District of Columbia'];
  const cities = ['New York', 'Los Angeles', 'Chicago', 'Houston', 'Phoenix', 'Philadelphia', 'San Antonio', 'San Diego', 'Dallas', 'San Jose', 'Austin', 'Jacksonville', 'Fort Worth', 'Columbus', 'San Francisco', 'Charlotte', 'Indianapolis', 'Seattle', 'Denver', 'Washington', 'Boston', 'Nashville', 'El Paso', 'Detroit', 'Portland', 'Las Vegas', 'Memphis', 'Louisville', 'Baltimore', 'Milwaukee', 'Albuquerque', 'Hartford', 'New Haven', 'Bridgeport'];

  let locationSnippet = "";
  const ldMatch = html.match(/<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi);

  if (ldMatch) {
      ldMatch.forEach(block => {
          const country = block.match(/"addressCountry"\s*:\s*"([^"]+)"/i);
          const region = block.match(/"addressRegion"\s*:\s*"([^"]+)"/i);
          const locality = block.match(/"addressLocality"\s*:\s*"([^"]+)"/i);
          locationSnippet += ` ${locality?.[1] || ""} ${region?.[1] || ""} ${country?.[1] || ""}`;
      });
  }

  if (!locationSnippet.trim()) {
      const meta = html.match(/<meta\s+(?:name|property)=["'](?:og:description|description|og:url|og:title)["']\s+content=["']([^"']+)["']/gi);
      if (meta) {
        meta.forEach(m => {
          const content = m.match(/content=["']([^"']+)["']/i);
          if (content) locationSnippet += " " + content[1];
        });
      }
      const title = html.match(/<title>([\s\S]*?)<\/title>/i);
      if (title) locationSnippet += " " + title[1];
  }

  if (!locationSnippet.trim()) {
      locationSnippet = html.substring(0, 4000);
  }

  const cleanSnippet = locationSnippet.replace(/[\/\-_.,]/g, ' ');
  const hasAbbr = stateAbbr.some(s => new RegExp(`\\b${s}\\b`).test(cleanSnippet));
  const hasFullState = stateFull.some(s => new RegExp(`\\b${s}\\b`, 'i').test(cleanSnippet));
  const hasCity = cities.some(c => new RegExp(`\\b${c}\\b`, 'i').test(cleanSnippet));
  const hasCountry = /\b(USA|U\.S\.A\.|US|U\.S\.)\b/.test(cleanSnippet) || /\bUnited States( of America)?\b/i.test(cleanSnippet);
  const isUS = hasAbbr || hasFullState || hasCity || hasCountry;
  return { yearsNum, yearsText, visaStatus, location: isUS ? "USA" : "International", isUS };
}

